#define M 3  // Order of B-Tree (max children per node)

typedef struct BTreeNode {
    int keys[M];
    int count;
    struct BTreeNode* children[M + 1];
    int leaf;
} BTreeNode;

BTreeNode* createNode(int leaf) {
    BTreeNode* node = (BTreeNode*)malloc(sizeof(BTreeNode));
    node->leaf = leaf;
    node->count = 0;
    for (int i = 0; i < M + 1; i++)
        node->children[i] = NULL;
    return node;
}

void traverse(BTreeNode* root) {
    if (root != NULL) {
        int i;
        for (i = 0; i < root->count; i++) {
            if (!root->leaf)
                traverse(root->children[i]);
            printf("%d ", root->keys[i]);
        }
        if (!root->leaf)
            traverse(root->children[i]);
    }
}

void splitChild(BTreeNode* parent, int i, BTreeNode* child) {
    BTreeNode* newChild = createNode(child->leaf);
    newChild->count = M / 2;

    for (int j = 0; j < M / 2; j++)
        newChild->keys[j] = child->keys[j + (M / 2) + 1];

    if (!child->leaf) {
        for (int j = 0; j < M / 2 + 1; j++)
            newChild->children[j] = child->children[j + (M / 2) + 1];
    }

    child->count = M / 2;

    for (int j = parent->count; j >= i + 1; j--)
        parent->children[j + 1] = parent->children[j];

    parent->children[i + 1] = newChild;

    for (int j = parent->count - 1; j >= i; j--)
        parent->keys[j + 1] = parent->keys[j];

    parent->keys[i] = child->keys[M / 2];
    parent->count++;
}

void insertNonFull(BTreeNode* node, int key) {
    int i = node->count - 1;

    if (node->leaf) {
        while (i >= 0 && key < node->keys[i]) {
            node->keys[i + 1] = node->keys[i];
            i--;
        }
        node->keys[i + 1] = key;
        node->count++;
    } else {
        while (i >= 0 && key < node->keys[i])
            i--;
        i++;
        if (node->children[i]->count == M) {
            splitChild(node, i, node->children[i]);
            if (key > node->keys[i])
                i++;
        }
        insertNonFull(node->children[i], key);
    }
}

BTreeNode* insert(BTreeNode* root, int key) {
    if (root->count == M) {
        BTreeNode* newRoot = createNode(0);
        newRoot->children[0] = root;
        splitChild(newRoot, 0, root);
        int i = 0;
        if (key > newRoot->keys[0])
            i++;
        insertNonFull(newRoot->children[i], key);
        return newRoot;
    } else {
        insertNonFull(root, key);
        return root;
    }
}

