Process pq[MAX];
int size = 0;

void enqueue(int pid, int burst, int priority) {
    if (size == MAX) {
        printf("Queue is full!\n");
        return;
    }
    pq[size].pid = pid;
    pq[size].burst = burst;
    pq[size].priority = priority;
    size++;
}

// Find highest priority process (lowest priority number = highest priority)
int getHighestPriorityIndex() {
    int i, minIndex = 0;
    for (i = 1; i < size; i++) {
        if (pq[i].priority < pq[minIndex].priority)
            minIndex = i;
    }
    return minIndex;
}

void schedule() {
    while (size > 0) {
        int idx = getHighestPriorityIndex();
        printf("Process P%d executed (Burst Time: %d, Priority: %d)\n", pq[idx].pid, pq[idx].burst, pq[idx].priority);
        for (int i = idx; i < size - 1; i++) {
            pq[i] = pq[i + 1];
        }
        size--;
    }
}

int main() {
