#include <stdio.h>
#include <stdlib.h>

#define MAX_CHILDREN 4

typedef struct Rect {
    int x1, y1, x2, y2; // bottom-left (x1,y1), top-right (x2,y2)
} Rect;

typedef struct RTreeNode {
    Rect mbr; // minimum bounding rectangle
    int isLeaf;
    int count;
    struct RTreeNode* children[MAX_CHILDREN];
    Rect rects[MAX_CHILDREN]; // only used if leaf
} RTreeNode;

RTreeNode* createNode(int isLeaf) {
    RTreeNode* node = (RTreeNode*)malloc(sizeof(RTreeNode));
    node->isLeaf = isLeaf;
    node->count = 0;
    node->mbr.x1 = node->mbr.y1 = 9999;
    node->mbr.x2 = node->mbr.y2 = -9999;
    for (int i = 0; i < MAX_CHILDREN; i++) {
        node->children[i] = NULL;
    }
    return node;
}

void updateMBR(RTreeNode* node, Rect r) {
    if (r.x1 < node->mbr.x1) node->mbr.x1 = r.x1;
    if (r.y1 < node->mbr.y1) node->mbr.y1 = r.y1;
    if (r.x2 > node->mbr.x2) node->mbr.x2 = r.x2;
    if (r.y2 > node->mbr.y2) node->mbr.y2 = r.y2;
}

void insertRect(RTreeNode* root, Rect r) {
    if (root->isLeaf) {
        if (root->count < MAX_CHILDREN) {
            root->rects[root->count++] = r;
            updateMBR(root, r);
        } else {
            printf("Leaf node full! Splitting not implemented in this demo.\n");
        }
    } else {
        // For simplicity, always insert into first child
        if (root->children[0] == NULL)
            root->children[0] = createNode(1);
        insertRect(root->children[0], r);
        updateMBR(root, r);
    }
}

int intersects(Rect a, Rect b) {
    return !(a.x2 < b.x1 || a.x1 > b.x2 || a.y2 < b.y1 || a.y1 > b.y2);
}

void searchRTree(RTreeNode* root, Rect query) {
    if (root == NULL) return;
    if (!intersects(root->mbr, query)) return;

    if (root->isLeaf) {
        for (int i = 0; i < root->count; i++) {
            if (intersects(root->rects[i], query)) {
                printf("Rectangle (%d,%d)-(%d,%d) intersects query.\n",
                       root->rects[i].x1, root->rects[i].y1,
                       root->rects[i].x2, root->rects[i].y2);
            }
        }
    } else {
        for (int i = 0; i < MAX_CHILDREN; i++) {
            searchRTree(root->children[i], query);
        }
    }
}

int main() {
    RTreeNode* root = createNode(1);

    Rect r1 = {1, 1, 3, 3};
    Rect r2 = {2, 2, 5, 5};
    Rect r3 = {6, 6, 8, 8};
    Rect r4 = {0, 0, 2, 2};

    insertRect(root, r1);
    insertRect(root, r2);
    insertRect(root, r3);
    insertRect(root, r4);

    Rect query = {2, 2, 6, 6};
    printf("Querying rectangles intersecting (%d,%d)-(%d,%d):\n", query.x1, query.y1, query.x2, query.y2);
    searchRTree(root, query);

    return 0;
}
